protected function isJsonRequest(Request $request): bool
    {
        // If XmlHttpRequest, Live or HTMX, return true
        if (
            $request->isXmlHttpRequest()
            || $request->headers->has('X-Livewire')
            || ($request->headers->has('Hx-Request') && $request->headers->has('Hx-Target'))
        ) {
            return true;
        }

        // Check if the request wants Json
        $acceptable = $request->getAcceptableContentTypes();
        if (isset($acceptable[0]) && in_array($acceptable[0], ['application/json', 'application/javascript'], true)) {
            return true;
        }

        return false;
    }

protected function isJsonResponse(SymfonyResponse $response): bool
    {
        if ($response instanceof JsonResponse || $response->headers->get('Content-Type') === 'application/json') {
            return true;
        }

        $content = $response->getContent();
        if (is_string($content)) {
            $content = trim($content);
            if ($content === '') {
                return false;
            }

            // Quick check to see if it looks like JSON
            $first = $content[0];
            $last  = $content[strlen($content) - 1];
            if (
                ($first === '{' && $last === '}')
                || ($first === '[' && $last === ']')
            ) {
                // Must contain a colon or comma
                return strpbrk($content, ':,') !== false;
            }
        }

        return false;
    }

public function collectMetaData(): array
    {
        $meta = [
            'id' => $this->getCurrentRequestId(),
            'datetime' => date('Y-m-d H:i:s'),
            'utime' => microtime(true),
            'method' => $this->request->getMethod(),
            'uri' => $this->request->getRequestUri(),
            'ip' => $this->request->getClientIp(),
        ];

        if ($this->processingJob) {
            $meta['method'] = 'JOB';
            $meta['uri'] =  $this->processingJob->resolveName() . '@' . $this->processingJob->getConnectionName();
        } elseif ($this->app->runningInConsole()) {
            $meta['method'] = 'CLI';
            $meta['uri'] = implode(' ', (new ArgvInput())->getRawTokens());
        }

        return $meta;
    }

protected function unpackDotProps(array $props): array
    {
        foreach ($props as $key => $value) {
            if (! is_string($key) || ! str_contains($key, '.')) {
                continue;
            }

            if ($value instanceof Closure) {
                $value = App::call($value);
            }

            if ($value instanceof Arrayable) {
                $value = $value->toArray();
            }

            $this->ensurePathIsTraversable($props, $key);
            Arr::set($props, $key, $value);
            unset($props[$key]);
        }

        return $props;
    }

public function append(bool|string|array $path = true, ?string $matchOn = null): static
    {
        match (true) {
            is_bool($path) => $this->append = $path,
            is_string($path) => $this->appendsAtPaths[] = $path,
            is_array($path) => collect($path)->each(
                fn ($value, $key) => is_numeric($key) ? $this->append($value) : $this->append($key, $value)
            ),
        };

        if (is_string($path) && $matchOn) {
            $this->matchOn([...$this->matchOn, "{$path}.{$matchOn}"]);
        }

        return $this;
    }

public function __construct(
    string $component,
    array $sharedProps,
    array $props,
    string $rootView = 'app',
    string $version = '',
    bool $encryptHistory = false,
    ?Closure $urlResolver = null,
) {
    $this->component = $component;
    $this->sharedProps = $sharedProps;
    $this->props = $props;
    $this->rootView = $rootView;
    $this->version = $version;
    $this->clearHistory = session()->pull(SessionKey::CLEAR_HISTORY, false);
    $this->preserveFragment = session()->pull(SessionKey::PRESERVE_FRAGMENT, false);
    $this->encryptHistory = $encryptHistory;
    $this->urlResolver = $urlResolver;
}

public function reload(?Closure $callback = null, array|string|null $only = null, array|string|null $except = null): self
    {
        if (is_array($only)) {
            $only = implode(',', $only);
        }

        if (is_array($except)) {
            $except = implode(',', $except);
        }

        $reloadRequest = new ReloadRequest(
            $this->url,
            $this->component,
            $this->version,
            $only,
            $except,
        );

        $assertable = AssertableInertia::fromTestResponse($reloadRequest());

        // Make sure we get the same data as the original request.
        $assertable->component($this->component);
        $assertable->url($this->url);
        $assertable->version($this->version);

        if ($callback) {
            $callback($assertable);
        }

        return $this;
    }

public static function getParameterClassName($parameter)
    {
        $type = $parameter->getType();

        if (! $type instanceof ReflectionNamedType || $type->isBuiltin()) {
            return null;
        }

        $name = $type->getName();

        if (! is_null($class = $parameter->getDeclaringClass())) {
            if ($name === 'self') {
                return $class->getName();
            }

            if ($name === 'parent' && $parent = $class->getParentClass()) {
                return $parent->getName();
            }
        }

        return $name;
    }

protected static function extractValuesForWildcards($masterData, $data, $attribute)
    {
        $keys = [];

        $pattern = str_replace('\*', '[^\.]+', preg_quote($attribute, '/'));

        foreach ($data as $key => $value) {
            if ((bool) preg_match('/^'.$pattern.'/', $key, $matches)) {
                $keys[] = $matches[0];
            }
        }

        $keys = array_unique($keys);

        $data = [];

        foreach ($keys as $key) {
            $data[$key] = Arr::get($masterData, $key);
        }

        return $data;
    }

protected function getTotalCount($results)
    {
        $engine = $this->engine();

        $totalCount = $engine->getTotalCount($results);

        if (is_null($this->queryCallback)) {
            return $totalCount;
        }

        $ids = $engine->mapIdsFrom($results, $this->model->getScoutKeyName())->all();

        if (count($ids) < $totalCount) {
            $ids = $engine->keys(tap(clone $this, function ($builder) use ($totalCount) {
                $builder->take(
                    is_null($this->limit) ? $totalCount : min($this->limit, $totalCount)
                );
            }))->all();
        }

        return $this->model->queryScoutModelsByIds(
            $this, $ids
        )->toBase()->getCountForPagination();
    }
